// Generate welcome packet
const customerName = $input.first().json.name;
const customerEmail = $input.first().json.email;
const plan = $input.first().json.plan || 'starter';
const company = $input.first().json.company || '';

const credentials = {
  username: customerEmail,
  tempPassword: Math.random().toString(36).slice(-10),
  loginUrl: 'https://app.yourcompany.com/login',
  dashboardUrl: 'https://app.yourcompany.com/dashboard'
};

const onboardingSteps = [
  { day: 1, task: 'Complete profile setup', status: 'pending' },
  { day: 2, task: 'Watch intro video (5 min)', status: 'pending' },
  { day: 3, task: 'Connect first integration', status: 'pending' },
  { day: 5, task: 'Schedule onboarding call', status: 'pending' },
  { day: 7, task: 'Review first-week report', status: 'pending' }
];

return [{
  json: {
    customerName,
    customerEmail,
    company,
    plan,
    credentials,
    onboardingSteps,
    onboardingId: 'ONB-' + Date.now(),
    createdAt: new Date().toISOString()
  }
}];
